def lcs_length(a, b):
    # O(n*m) dynamic programming - but strings are short
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        ai = a[i-1]
        for j in range(1, m+1):
            temp = dp[j]
            if ai == b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = temp
    return dp[m]

def lcs_similarity(a, b):
    L = lcs_length(a, b)
    return (2*L) / (len(a) + len(b)) if (len(a)+len(b))>0 else 0.0

